<script setup lang="ts">import {Connection,Delete,Plus} from '@element-plus/icons-vue';import {onMounted,reactive,ref} from 'vue';import {ElMessage} from 'element-plus';import {api} from '@/api/client';const tab=ref('cities'),rows=ref<any[]>([]),dialog=ref(false),form=reactive<any>({});async function load(){rows.value=(await api.settings(tab.value)).data.data}function add(){Object.keys(form).forEach(k=>delete form[k]);dialog.value=true}async function save(){await api.createSetting(tab.value,form);dialog.value=false;load()}async function remove(id:number){await api.deleteSetting(tab.value,id);load()}async function test(){try{await api.testOpenCLI();ElMessage.success('OpenCLI 登录与连接正常')}catch(e:any){ElMessage.error(e.response?.data?.message||'请在 Chrome 登录小红书')}}onMounted(load)</script>
<template><ElCard shadow="never"><div class="toolbar"><ElRadioGroup v-model="tab" @change="load"><ElRadioButton value="cities">城市</ElRadioButton><ElRadioButton value="keywords">关键词</ElRadioButton><ElRadioButton value="bloggers">博主</ElRadioButton></ElRadioGroup><ElButton type="primary" :icon="Plus" @click="add">新增</ElButton><ElButton :icon="Connection" @click="test">测试 OpenCLI</ElButton></div><ElTable :data="rows"><ElTableColumn v-for="key in Object.keys(rows[0]||{}).filter(x=>!['created_at'].includes(x))" :key="key" :prop="key" :label="key"/><ElTableColumn label="操作"><template #default="s"><ElButton text type="danger" :icon="Delete" @click="remove(s.row.id)">删除</ElButton></template></ElTableColumn></ElTable></ElCard><ElDialog v-model="dialog" title="新增配置"><ElForm label-width="130"><template v-if="tab==='cities'"><ElFormItem label="城市名称"><ElInput v-model="form.name"/></ElFormItem><ElFormItem label="城市代码"><ElInput v-model="form.code"/></ElFormItem></template><template v-if="tab==='keywords'"><ElFormItem label="关键词"><ElInput v-model="form.word"/></ElFormItem><ElFormItem label="城市代码"><ElInput v-model="form.city_code"/></ElFormItem></template><template v-if="tab==='bloggers'"><ElFormItem label="用户 ID"><ElInput v-model="form.platform_user_id"/></ElFormItem><ElFormItem label="名称"><ElInput v-model="form.username"/></ElFormItem><ElFormItem label="主页"><ElInput v-model="form.profile_url"/></ElFormItem><ElFormItem label="城市代码"><ElInput v-model="form.city_code"/></ElFormItem></template></ElForm><template #footer><ElButton @click="dialog=false">取消</ElButton><ElButton type="primary" @click="save">保存</ElButton></template></ElDialog></template>
